# 8. Fix Recommendations

# Primary Fix: Validate and clamp lengths

```c
/* Validate namelen and valuelen before use */
int safe_namelen, safe_valuelen;

/* Check for negative or overflow */
if(namelen < 0 || namelen > INT_MAX) {
    H2BUGF(infof(data_s, "h2 trailer: name length %zu out of range", 
                 (size_t)namelen));
    return NGHTTP2_ERR_CALLBACK_FAILURE;
}

if(valuelen < 0 || valuelen > INT_MAX) {
    H2BUGF(infof(data_s, "h2 trailer: value length %zu out of range", 
                 (size_t)valuelen));
    return NGHTTP2_ERR_CALLBACK_FAILURE;
}

safe_namelen = (int)namelen;
safe_valuelen = (int)valuelen;

result = Curl_dyn_addf(&stream->trailer_recvbuf,
                       "%.*s: %.*s\r\n", 
                       safe_namelen, name,
                       safe_valuelen, value);
```

# Alternative Fix: Use dynamic string functions without printf

```c
/* Avoid printf entirely for better safety */
result = Curl_dyn_addn(&stream->trailer_recvbuf, name, namelen);
if(result) return NGHTTP2_ERR_CALLBACK_FAILURE;

result = Curl_dyn_addn(&stream->trailer_recvbuf, STRCONST(": "));
if(result) return NGHTTP2_ERR_CALLBACK_FAILURE;

result = Curl_dyn_addn(&stream->trailer_recvbuf, value, valuelen);
if(result) return NGHTTP2_ERR_CALLBACK_FAILURE;

result = Curl_dyn_addn(&stream->trailer_recvbuf, STRCONST("\r\n"));
if(result) return NGHTTP2_ERR_CALLBACK_FAILURE;
```

